// Syncs committed Android customizations into the gitignored, regenerable
// src-tauri/gen/ tree. Runs from tauri.conf.json beforeBuildCommand (and is
// safe to run manually: `npm run sync-android`). No-ops when gen/android
// doesn't exist (desktop-only checkouts, pre-init state).
//
// Covers two of the three post-`android init` steps in docs/ANDROID-BUILD-NOTES.md:
//   1. Kotlin plugin sources (android-extras/*.kt → app package .plugin subdir)
//   2. AndroidManifest.xml media permissions (idempotent insert)
// Icons remain a manual step (binary assets, regenerated by `tauri icon`).

import { copyFileSync, existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const genAndroid = join(root, 'src-tauri', 'gen', 'android');

if (!existsSync(genAndroid)) {
	console.log('[sync-android-extras] no gen/android — skipping');
	process.exit(0);
}

// 1. Kotlin extras → app module, plugin subpackage
const extrasDir = join(root, 'src-tauri', 'android-extras');
const pluginDir = join(genAndroid, 'app', 'src', 'main', 'java', 'com', 'audhd', 'resonance_compass', 'plugin');
if (existsSync(extrasDir)) {
	mkdirSync(pluginDir, { recursive: true });
	for (const file of readdirSync(extrasDir).filter((f) => f.endsWith('.kt'))) {
		copyFileSync(join(extrasDir, file), join(pluginDir, file));
		console.log(`[sync-android-extras] synced ${file}`);
	}
}

// 2. Manifest permissions (READ_MEDIA_AUDIO for 33+, READ_EXTERNAL_STORAGE ≤32)
const manifestPath = join(genAndroid, 'app', 'src', 'main', 'AndroidManifest.xml');
const manifest = readFileSync(manifestPath, 'utf8');
if (!manifest.includes('READ_MEDIA_AUDIO')) {
	const internetLine = '<uses-permission android:name="android.permission.INTERNET" />';
	if (!manifest.includes(internetLine)) {
		console.error('[sync-android-extras] manifest INTERNET anchor not found — add permissions manually');
		process.exit(1);
	}
	const block =
		internetLine +
		'\n    <!-- Android 13+ audio access (API 33+) -->' +
		'\n    <uses-permission android:name="android.permission.READ_MEDIA_AUDIO" />' +
		'\n    <!-- Android 12 and below storage access -->' +
		'\n    <uses-permission android:name="android.permission.READ_EXTERNAL_STORAGE" android:maxSdkVersion="32" />';
	writeFileSync(manifestPath, manifest.replace(internetLine, block));
	console.log('[sync-android-extras] manifest permissions inserted');
} else {
	console.log('[sync-android-extras] manifest permissions already present');
}

// 3. RECORD_AUDIO (v3 Phase 2 — the microphone), idempotent like the rest
const manifest2 = readFileSync(manifestPath, 'utf8');
if (!manifest2.includes('RECORD_AUDIO')) {
	const anchor = '<uses-permission android:name="android.permission.READ_MEDIA_AUDIO" />';
	if (!manifest2.includes(anchor)) {
		console.error('[sync-android-extras] READ_MEDIA_AUDIO anchor not found — add RECORD_AUDIO manually');
		process.exit(1);
	}
	const micBlock =
		anchor +
		'\n    <!-- v3 recording (the Musician\'s Compass) — microphone -->' +
		'\n    <uses-permission android:name="android.permission.RECORD_AUDIO" />';
	writeFileSync(manifestPath, manifest2.replace(anchor, micBlock));
	console.log('[sync-android-extras] RECORD_AUDIO inserted');
} else {
	console.log('[sync-android-extras] RECORD_AUDIO already present');
}
